SELECT count(*) FROM title, cast_info, movie_info, info_type, char_name, role_type, movie_companies WHERE cast_info.movie_id = title.id AND movie_info.movie_id = title.id AND movie_info.info_type_id = info_type.id AND cast_info.person_role_id = char_name.id AND cast_info.role_id = role_type.id AND movie_companies.movie_id = title.id;